use serde::{Deserialize, Serialize};
use std::fs::{self, File};
use std::io::{self, Write};
use std::sync::{Arc, Mutex};
use tokio::task;
use tokio::sync::mpsc;

#[derive(Serialize, Deserialize, Debug, Clone)]
struct InventoryItem {
    product: String,
    store: String,
    quantity: u32,
}

type Inventory = Arc<Mutex<Vec<InventoryItem>>>;

async fn load_inventory(file_path: &str) -> io::Result<Inventory> {
    let data = fs::read_to_string(file_path)?;
    let inventory: Vec<InventoryItem> = serde_json::from_str(&data)?;
    Ok(Arc::new(Mutex::new(inventory)))
}

async fn save_inventory(file_path: &str, inventory: Inventory) -> io::Result<()> {
    let data = {
        let inventory = inventory.lock().unwrap();
        serde_json::to_string(&*inventory)?
    };
    let mut file = File::create(file_path)?;
    file.write_all(data.as_bytes())?;
    Ok(())
}

async fn handle_updates(inventory: Inventory, mut rx: mpsc::Receiver<(String, String, u32)>) {
    while let Some((product, store, quantity)) = rx.recv().await {
        let mut inventory = inventory.lock().unwrap();
        if let Some(item) = inventory.iter_mut().find(|i| i.product == product && i.store == store) {
            item.quantity = quantity;
        } else {
            inventory.push(InventoryItem { product, store, quantity });
        }
    }
}

#[tokio::main]
async fn main() -> io::Result<()> {
    let file_path = "inventory.json";
    let inventory = load_inventory(file_path).await?;
    let (tx, rx) = mpsc::channel(32);

    let inventory_clone = Arc::clone(&inventory);
    tokio::spawn(async move {
        handle_updates(inventory_clone, rx).await;
    });

    loop {
        println!("Enter update in the format: <product> <store> <quantity>");
        let mut input = String::new();
        io::stdin().read_line(&mut input)?;
        let parts: Vec<&str> = input.trim().split_whitespace().collect();
        if parts.len() != 3 {
            println!("Invalid input. Try again.");
            continue;
        }

        let product = parts[0].to_string();
        let store = parts[1].to_string();
        let quantity: u32 = match parts[2].parse() {
            Ok(q) => q,
            Err(_) => {
                println!("Invalid quantity. Try again.");
                continue;
            }
        };

        if let Err(_) = tx.send((product, store, quantity)).await {
            println!("Failed to send the update.");
        }

        save_inventory(file_path, Arc::clone(&inventory)).await?;
    }
}
