use std::fs::{File, OpenOptions};
use std::io::{self, BufReader, BufRead};
use std::sync::{Arc, Mutex};
use std::thread;
use std::collections::HashMap;
use serde_json::Value;

fn process_log_line(line: &str) -> Option<(String, u64)> {
    let json_data: Value = serde_json::from_str(line).ok()?;
    let status = json_data["status"].as_str()?.to_string();
    let response_time = json_data["response_time"].as_u64()?;

    Some((status, response_time))
}

fn analyze_logs(input_files: Vec<String>) {
    let metrics = Arc::new(Mutex::new(HashMap::new()));

    let handles: Vec<_> = input_files.iter().map(|file_name| {
        let metrics = Arc::clone(&metrics);

        thread::spawn(move || {
            let file = OpenOptions::new().read(true).open(file_name).expect("Unable to open file");
            let reader = BufReader::new(file);

            for line in reader.lines() {
                if let Ok(line) = line {
                    if let Some((status, response_time)) = process_log_line(&line) {
                        let mut metrics = metrics.lock().unwrap();
                        metrics.entry(status).or_insert_with(Vec::new).push(response_time);
                    }
                }
            }
        })
    }).collect();

    for handle in handles {
        let _ = handle.join();
    }

    let metrics = metrics.lock().unwrap();
    println!("{:?}", *metrics);
}

fn main() {
    let log_files = vec![
        String::from("server1.log"),
        // Add paths to log files from up to 100 servers here
    ];

    analyze_logs(log_files);
}
