import com.sun.net.httpserver.HttpServer;
import com.sun.net.httpserver.HttpHandler;
import com.sun.net.httpserver.HttpExchange;
import java.io.InputStreamReader;
import java.io.OutputStream;
import java.net.InetSocketAddress;
import java.nio.charset.StandardCharsets;
import java.util.stream.Collectors;
import org.json.JSONObject;

public class SentimentAnalysisService {

    static final class SentimentResult {
        private final String sentiment;

        public SentimentResult(String sentiment) {
            this.sentiment = sentiment;
        }

        public String sentiment() {
            return sentiment;
        }
    }

    static final class SentimentHandler implements HttpHandler {
        @Override
        public void handle(HttpExchange exchange) {
            if ("POST".equals(exchange.getRequestMethod())) {
                try (var reader = new InputStreamReader(exchange.getRequestBody(), StandardCharsets.UTF_8)) {
                    String body = new String(reader.readAllChars());
                    JSONObject json = new JSONObject(body);
                    String text = json.getString("text");

                    String result = analyzeSentiment(text);
                    SentimentResult sentimentResult = new SentimentResult(result);

                    JSONObject responseJson = new JSONObject();
                    responseJson.put("sentiment", sentimentResult.sentiment());

                    byte[] responseBytes = responseJson.toString().getBytes(StandardCharsets.UTF_8);

                    exchange.getResponseHeaders().set("Content-Type", "application/json");
                    exchange.sendResponseHeaders(200, responseBytes.length);
                    try (OutputStream os = exchange.getResponseBody()) {
                        os.write(responseBytes);
                    }
                } catch (Exception e) {
                    sendError(exchange, "Invalid request");
                }
            } else {
                sendError(exchange, "Method not allowed");
            }
        }

        private String analyzeSentiment(String text) {
            int positiveWords = text.split("(?i)\\b(good|great|happy|excellent|positive)\\b").length - 1;
            int negativeWords = text.split("(?i)\\b(bad|terrible|sad|poor|negative)\\b").length - 1;

            return positiveWords == negativeWords ? "neutral"
                    : (positiveWords > negativeWords ? "positive" : "negative");
        }

        private void sendError(HttpExchange exchange, String message) {
            try {
                exchange.sendResponseHeaders(400, message.length());
                exchange.getResponseBody().write(message.getBytes(StandardCharsets.UTF_8));
            } catch (Exception ignored) {
            } finally {
                exchange.close();
            }
        }
    }

    public static void main(String[] args) throws Exception {
        HttpServer server = HttpServer.create(new InetSocketAddress(8080), 0);
        server.createContext("/analyze", new SentimentHandler());
        System.out.println("Server running on http://localhost:8080/analyze");
        server.start();
    }
}
