use std::sync::{Arc, Mutex};
use std::fs::OpenOptions;
use std::io::{Write};
use tokio::net::{TcpListener, TcpStream};
use tokio::sync::mpsc;
use tokio_tungstenite::{accept_async, tungstenite::Message};

type Tx = mpsc::Sender<Message>;
type Rx = mpsc::Receiver<Message>;

#[tokio::main]
async fn main() {
    let addr = "127.0.0.1:8080";
    let listener = TcpListener::bind(addr).await.expect("Failed to bind");
    let clients = Arc::new(Mutex::new(HashMap::new()));
    let log_file = Arc::new(Mutex::new(
        OpenOptions::new()
            .create(true)
            .append(true)
            .open("chat_history.log")
            .expect("Failed to open file"),
    ));

    println!("WebSocket server listening on {}", addr);

    while let Ok((stream, _)) = listener.accept().await {
        let clients = Arc::clone(&clients);
        let log_file = Arc::clone(&log_file);

        tokio::spawn(async move {
            if let Err(e) = handle_connection(stream, clients, log_file).await {
                eprintln!("Connection error: {}", e);
            }
        });
    }
}

async fn handle_connection(
    stream: TcpStream,
    clients: Arc<Mutex<HashMap<usize, Tx>>>,
    log_file: Arc<Mutex<std::fs::File>>,
) -> tokio_tungstenite::tungstenite::Result<()> {
    let ws_stream = accept_async(stream).await?;
    let (tx, mut rx) = mpsc::channel(100);

    let mut id = 0;
    {
        let mut clients_lock = clients.lock().unwrap();
        id = clients_lock.len() + 1;
        if id > 100 {
            return Err(tokio_tungstenite::tungstenite::Error::Io(std::io::Error::new(
                std::io::ErrorKind::Other,
                "Too many connections",
            )));
        }
        clients_lock.insert(id, tx);
    }

    let (mut write, mut read) = ws_stream.split();

    tokio::spawn(async move {
        while let Some(message) = rx.recv().await {
            if let Err(e) = write.send(message).await {
                eprintln!("Failed to send message: {}", e);
            }
        }
    });

    while let Some(Ok(message)) = read.next().await {
        let clients_lock = clients.lock().unwrap();
        for (&client_id, client_tx) in clients_lock.iter() {
            if client_id != id {
                let _ = client_tx.send(message.clone()).await;
            }
        }

        let mut log_file_lock = log_file.lock().unwrap();
        writeln!(log_file_lock, "Client {}: {}", id, message).expect("Failed to write to log");
    }

    clients.lock().unwrap().remove(&id);
    Ok(())
}
