import java.util.HashMap;

public class DataRetentionService {

    private DatabaseConnection databaseConnection;

    private HashMap<String, RetentionPolicy> retentionPolicies = new HashMap<>();

    public DataRetentionService(DatabaseConnection databaseConnection) {
        this.databaseConnection = databaseConnection;
    }

    public void addRetentionPolicy(String tableName, RetentionPolicy policy) {
        retentionPolicies.put(tableName, policy);
    }

    public void enforceRetentionPolicy() {
        for (var entry : retentionPolicies.entrySet()) {
            String tableName = entry.getKey();
            RetentionPolicy policy = entry.getValue();

            Object tableDataInfo = databaseConnection.getTableDataInfo(tableName);

            switch (tableDataInfo) {
                case SQLTableInfo sqlTable -> databaseConnection.purgeSqlData(sqlTable, policy);
                case NoSQLTableInfo nosqlTable -> databaseConnection.purgeNoSqlData(nosqlTable, policy);
                default -> System.out.println("Unknown table type for table: " + tableName);
            }
        }
    }

    public static void main(String[] args) {
        DatabaseConnection dbConnection = new DatabaseConnection();
        DataRetentionService service = new DataRetentionService(dbConnection);

        // Configure retention policies
        service.addRetentionPolicy("user_data", new RetentionPolicy("user_data", 30)); // 30 days
        service.addRetentionPolicy("session_logs", new RetentionPolicy("session_logs", 7)); // 7 days

        // Automatically enforce retention policies
        service.enforceRetentionPolicy();
    }
}

interface DatabaseConnection {
    Object getTableDataInfo(String tableName);

    void purgeSqlData(SQLTableInfo tableInfo, RetentionPolicy policy);

    void purgeNoSqlData(NoSQLTableInfo tableInfo, RetentionPolicy policy);
}

record SQLTableInfo(String name, String schema) {}
record NoSQLTableInfo(String name, String collection) {}

record RetentionPolicy(String tableName, int durationDays) {}
