    id: u32,
    message: String,
    timestamp: u64,
}

async fn process_files(directory: &str) -> io::Result<()> {
    let paths = fs::read_dir(directory)?;

    let mut tasks = vec![];

    for path in paths {
        let entry = path?;
        let path = entry.path();
        if path.extension().map_or(false, |ext| ext == "log") {
            let task = task::spawn(async move {
                match migrate_file(path.to_str().unwrap()).await {
                    Ok(_) => println!("Migrated: {}", path.display()),
                    Err(err) => eprintln!("Failed to migrate {}: {:?}", path.display(), err),
                }
            });
            tasks.push(task);
        }
    }

    for task in tasks {
        task.await?;
    }

    Ok(())
}

async fn migrate_file(file_path: &str) -> io::Result<()> {
    let mut file = File::open(file_path)?;

    let mut buffer = Vec::new();
    file.read_to_end(&mut buffer)?;

    let log_data: LogData = serde_json::from_slice(&buffer)?;

    let binary_data = bincode::serialize(&log_data)?;

    let bin_path = Path::new(file_path).with_extension("bin");
    let mut bin_file = File::create(&bin_path)?;
    bin_file.write_all(&binary_data)?;

    Ok(())
}

fn main() -> io::Result<()> {
    let rt = Runtime::new()?;

    rt.block_on(async {
        process_files("./logs").await
    })
}
