import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.SQLException;
import java.sql.Statement;
import java.sql.ResultSet;
import java.util.logging.Logger;
import org.json.JSONArray;
import org.json.JSONObject;

public class StockMarketAnalyzer {
    private static final Logger logger = Logger.getLogger(StockMarketAnalyzer.class.getName());
    private static final String DATABASE_URL = "jdbc:sqlite:stock_data.db";

    public static void main(String[] args) {
        try {
            Connection conn = connectDatabase();
            createTable(conn);

            JSONArray stockData = fetchStockData();
            analyzeAndStoreData(stockData, conn);

            conn.close();
        } catch (Exception e) {
            logger.severe("Error: " + e.getMessage());
        }
    }

    private static Connection connectDatabase() throws SQLException {
        logger.info("Connecting to the database...");
        return DriverManager.getConnection(DATABASE_URL);
    }

    private static void createTable(Connection conn) throws SQLException {
        logger.info("Creating table...");
        String sql = "CREATE TABLE IF NOT EXISTS stock_analysis (" +
                     "id INTEGER PRIMARY KEY AUTOINCREMENT, " +
                     "average_price REAL, " +
                     "max_price REAL, " +
                     "min_price REAL)";
        try (Statement stmt = conn.createStatement()) {
            stmt.execute(sql);
        }
    }

    private static JSONArray fetchStockData() throws Exception {
        logger.info("Fetching stock data...");
        HttpClient client = HttpClient.newHttpClient();
        HttpRequest request = HttpRequest.newBuilder()
                .uri(new URI("https://api.example.com/stockdata"))
                .build();

        HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());
        return new JSONArray(response.body());
    }

    private static void analyzeAndStoreData(JSONArray stockData, Connection conn) throws SQLException {
        logger.info("Analyzing and storing data...");
        double sum = 0;
        double max = Double.MIN_VALUE;
        double min = Double.MAX_VALUE;
        int count = stockData.length();

        for (int i = 0; i < count; i++) {
            JSONObject stock = stockData.getJSONObject(i);
            double price = stock.getDouble("price");
            sum += price;
            if (price > max) max = price;
            if (price < min) min = price;
        }

        double average = sum / count;

        String sql = "INSERT INTO stock_analysis (average_price, max_price, min_price) VALUES (?, ?, ?)";
        try (PreparedStatement pstmt = conn.prepareStatement(sql)) {
            pstmt.setDouble(1, average);
            pstmt.setDouble(2, max);
            pstmt.setDouble(3, min);
            pstmt.executeUpdate();
        }

        logger.info("Data stored successfully.");
    }
}
