use tokio::net::TcpListener;
use tokio::prelude::*;
use tokio::fs::File;
use tokio::io::AsyncReadExt;
use mime_guess::from_path;
use std::path::Path;
use std::sync::Arc;

#[tokio::main]
async fn main() -> std::io::Result<()> {
    let listener = TcpListener::bind("127.0.0.1:8080").await?;
    let pool = tokio::task::LocalSet::new();

    loop {
        let (socket, _) = listener.accept().await?;
        pool.spawn_local(handle_connection(socket));
    }
}

async fn handle_connection(mut socket: tokio::net::TcpStream) {
    let mut buffer = [0; 1024];
    if let Ok(_) = socket.read(&mut buffer).await {
        let request = String::from_utf8_lossy(&buffer[..]);
        if request.starts_with("GET /") {
            let request_line: Vec<&str> = request.split_whitespace().collect();
            let path = if request_line.len() > 1 {
                request_line[1].trim_start_matches('/')
            } else {
                "index.html"
            };
            serve_file(&path, socket).await;
        }
    }
}

async fn serve_file(path: &str, mut socket: tokio::net::TcpStream) {
    let path = Path::new(path);
    if let Ok(mut file) = File::open(path).await {
        let mime_type = from_path(path).first_or_octet_stream();
        let mut file_bytes = vec![];
        if let Ok(_) = file.read_to_end(&mut file_bytes).await {
            let response = format!(
                "HTTP/1.1 200 OK\r\nContent-Type: {}\r\nContent-Length: {}\r\n\r\n",
                mime_type,
                file_bytes.len()
            );
            let response = Arc::new(response.into_bytes());
            let _ = socket.write_all(&response).await;
            let _ = socket.write_all(&file_bytes).await;
        }
    } else {
        let response = "HTTP/1.1 404 NOT FOUND\r\n\r\n";
        let _ = socket.write_all(response.as_bytes()).await;
    }
}
