use std::{
    collections::HashMap,
    path::PathBuf,
    sync::mpsc::{channel, Receiver},
    time::Duration,
};
use tokio::task;
use tokio::time::Instant;
use lettre::message::{header, Mailbox, Message};
use lettre::{SmtpTransport, Transport};

#[derive(Debug)]
struct Config {
    directories: Vec<PathBuf>,
    smtp_server: String,
    email_from: Mailbox,
    email_to: Mailbox,
    smtp_user: String,
    smtp_password: String,
}

async fn watch_directories(config: Config) {
    let mut watchers = HashMap::new();
    let (tx, rx): (std::sync::mpsc::Sender<DebouncedEvent>, Receiver<DebouncedEvent>) = channel();

    // Initialize watchers for each directory
    for dir in &config.directories {
        let mut watcher = watcher(tx.clone(), Duration::from_secs(1)).unwrap();
        watcher.watch(dir, RecursiveMode::Recursive).unwrap();
        watchers.insert(dir.clone(), watcher);
    }

    loop {
        if let Ok(event) = rx.recv() {
            if let DebouncedEvent::Create(path) = event {
                let now = Instant::now();

                // Send email notification
                let smtp_transport = SmtpTransport::relay(&config.smtp_server)
                    .unwrap()
                    .credentials((&config.smtp_user, &config.smtp_password))
                    .build();

                let email = Message::builder()
                    .from(config.email_from.clone())
                    .to(config.email_to.clone())
                    .subject("New file detected")
                    .header(header::ContentType::TEXT_PLAIN)
                    .body(format!(
                        "New file detected:\nPath: {}\nDetected at: {:?}",
                        path.display(),
                        now.elapsed()
                    ))
                    .unwrap();

                let _ = smtp_transport.send(&email);
                println!("Alert sent for file: {}", path.display());
            }
        }
    }
}

#[tokio::main]
async fn main() {
    let config = Config {
        directories: vec![
            PathBuf::from("/path/to/dir1"),
            PathBuf::from("/path/to/dir2"),
        ],
        smtp_server: "smtp.example.com".to_string(),
        email_from: "your_email@example.com".parse().unwrap(),
        email_to: "alert_receiver@example.com".parse().unwrap(),
        smtp_user: "your_username".to_string(),
        smtp_password: "your_password".to_string(),
    };

    watch_directories(config).await;
}
