import os
import time
import asyncio
import aiohttp
from datetime import datetime, timedelta

API_URL = "https://api.cloudstorage.com/upload"
API_KEY = "your_api_key"
LOCAL_PATH = "./local_files"

async def upload_file(session, file_path):
    try:
        async with session.post(
            API_URL,
            headers={"Authorization": f"Bearer {API_KEY}"},
            data={"file": open(file_path, 'rb')}
        ) as response:
            if response.status == 200:
                return file_path, "Success"
            else:
                return file_path, f"Failed: {response.status}"
    except Exception as e:
        return file_path, f"Error: {str(e)}"

async def backup_files():
    report = []
    now = datetime.now()
    last_24_hours = now - timedelta(days=1)
    async with aiohttp.ClientSession() as session:
        tasks = []
        for root, _, files in os.walk(LOCAL_PATH):
            for file in files:
                file_path = os.path.join(root, file)
                if os.path.isfile(file_path):
                    modified_time = datetime.fromtimestamp(os.path.getmtime(file_path))
                    if modified_time > last_24_hours:
                        tasks.append(upload_file(session, file_path))
        results = await asyncio.gather(*tasks)
        for file_path, status in results:
            report.append(f"File: {file_path}, Status: {status}")
    return report

async def main():
    try:
        report = await backup_files()
        print("Backup Report:")
        for entry in report:
            print(entry)
    except Exception as e:
        print(f"Unhandled error: {str(e)}")

if __name__ == "__main__":
    asyncio.run(main())
