use clap::Parser;
use serde::Serialize;
use std::fs::OpenOptions;
use std::io::Write;
use std::time::Duration;
use sysinfo::{DiskExt, System, SystemExt};
use tokio::time::interval;

#[derive(Parser)]
struct Config {
    /// Path to the log file
    #[arg(short, long)]
    log_path: String,
}

#[derive(Serialize)]
struct ResourceUsage {
    cpu_usage: f32,
    memory_usage: u64,
    disk_usage: u64,
}

async fn monitor_resources(log_path: String) -> Result<(), Box<dyn std::error::Error>> {
    let mut system = System::new_all();
    let mut interval = interval(Duration::from_secs(60));

    loop {
        interval.tick().await;
        system.refresh_all();

        let cpu_usage = system.global_processor_info().cpu_usage();
        let memory_usage = system.used_memory();
        let disk_usage: u64 = system.disks().iter().map(|d| d.total_space() - d.available_space()).sum();

        let usage = ResourceUsage {
            cpu_usage,
            memory_usage,
            disk_usage,
        };

        let mut file = OpenOptions::new()
            .create(true)
            .append(true)
            .open(&log_path)?;

        let record = serde_json::to_string(&usage)? + "\n";
        file.write_all(record.as_bytes())?;
    }
}

#[tokio::main]
async fn main() {
    let config = Config::parse();

    if let Err(e) = monitor_resources(config.log_path).await {
        eprintln!("Error: {:?}", e);
    }
}
