#[tokio::main]
async fn main() {
    let data: Arc<Mutex<HashMap<String, i64>>> = Arc::new(Mutex::new(HashMap::new()));

    let update_data = data.clone();
    let update_route = warp::post()
        .and(warp::body::json())
        .map(move |body: Value| {
            if let Some(map) = body.as_object() {
                let mut data = update_data.lock().unwrap();
                for (key, value) in map {
                    if let Some(num) = value.as_i64() {
                        data.entry(key.clone()).and_modify(|e| *e += num).or_insert(num);
                    }
                }
                warp::reply::json(&*data)
            } else {
                log::error!("Malformed JSON received.");
                warp::reply::with_status("Malformed JSON", warp::http::StatusCode::BAD_REQUEST)
            }
        });

    let routes = update_route.with(warp::log("warp::server"));

    let addr: SocketAddr = ([127, 0, 0, 1], 3030).into();
    warp::serve(routes).run(addr).await;
}
