import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.SQLException;
import java.sql.Statement;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.ExecutionException;
import org.json.JSONArray;
import org.json.JSONObject;

public class AnalyticsEngine {
    private static final String API_URL = "https://api.example.com/transactions";
    private static final String SQLITE_URL = "jdbc:sqlite:analytics.db";

    public static void main(String[] args) throws Exception {
        HttpClient client = HttpClient.newHttpClient();
        HttpRequest request = HttpRequest.newBuilder()
                .uri(new URI(API_URL))
                .build();

        CompletableFuture<HttpResponse<String>> responseFuture = client.sendAsync(request, HttpResponse.BodyHandlers.ofString());

        CompletableFuture<Void> processFuture = responseFuture.thenApply(HttpResponse::body)
                .thenApply(AnalyticsEngine::processData)
                .thenAccept(AnalyticsEngine::storeResults);

        processFuture.get(); // Wait for completion
    }

    private static JSONObject processData(String jsonString) {
        JSONArray transactions = new JSONArray(jsonString);

        double sum = 0;
        double max = Double.MIN_VALUE;

        for (int i = 0; i < transactions.length(); i++) {
            JSONObject transaction = transactions.getJSONObject(i);
            double amount = transaction.getDouble("amount");
            sum += amount;
            if (amount > max) {
                max = amount;
            }
        }

        double average = sum / transactions.length();

        JSONObject result = new JSONObject();
        result.put("sum", sum);
        result.put("average", average);
        result.put("max", max);
        return result;
    }

    private static void storeResults(JSONObject results) {
        try (Connection conn = DriverManager.getConnection(SQLITE_URL);
             Statement stmt = conn.createStatement()) {

            // Initialize SQLite table
            String createTableSQL = "CREATE TABLE IF NOT EXISTS analytics (id INTEGER PRIMARY KEY, sum REAL, average REAL, max REAL)";
            stmt.execute(createTableSQL);

            // Insert results
            String insertSQL = "INSERT INTO analytics (sum, average, max) VALUES (?, ?, ?)";
            try (PreparedStatement pstmt = conn.prepareStatement(insertSQL)) {
                pstmt.setDouble(1, results.getDouble("sum"));
                pstmt.setDouble(2, results.getDouble("average"));
                pstmt.setDouble(3, results.getDouble("max"));
                pstmt.executeUpdate();
            }
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}
