import java.nio.file.*;
import java.util.concurrent.*;
import net.sourceforge.tess4j.*;
import static java.nio.file.StandardWatchEventKinds.*;

public class DirectoryOCRMonitor {
    private static final ExecutorService executor = Executors.newFixedThreadPool(Runtime.getRuntime().availableProcessors());

    public static void main(String[] args) throws IOException {
        Path dir = Paths.get("watched_directory");
        if (!Files.exists(dir)) {
            Files.createDirectories(dir);
        }

        WatchService watchService = FileSystems.getDefault().newWatchService();
        dir.register(watchService, ENTRY_CREATE);

        System.out.println("Monitoring directory: " + dir);
        while (true) {
            try {
                WatchKey key = watchService.take();
                for (WatchEvent<?> event : key.pollEvents()) {
                    if (event.kind() == ENTRY_CREATE) {
                        Path filePath = dir.resolve((Path) event.context());
                        processFile(filePath);
                    }
                }
                key.reset();
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                executor.shutdown();
                break;
            }
        }
    }

    private static void processFile(Path filePath) {
        executor.submit(() -> {
            System.out.println("Processing file: " + filePath);
            if (Files.isRegularFile(filePath) && filePath.toString().endsWith(".jpg")) { // Assuming .jpg as image extension
                try {
                    Tesseract tesseract = new Tesseract();
                    tesseract.setDatapath("tessdata"); // Path to Tesseract language data
                    String result = tesseract.doOCR(filePath.toFile());

                    Path textFile = Paths.get(filePath.getParent().toString(), filePath.getFileName().toString().replace(".jpg", ".txt"));
                    Files.writeString(textFile, result);
                    System.out.println("OCR completed. Text saved to: " + textFile);
                } catch (TesseractException e) {
                    System.err.println("Error during OCR: " + e.getMessage());
                } catch (IOException e) {
                    System.err.println("File writing error: " + e.getMessage());
                }
            } else {
                System.out.println("Skipped non-image file: " + filePath);
            }
        });
    }
}
