import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.time.Duration;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.ThreadLocalRandom;

public class StockMarketSimulation {

    // Sealed class for stock types
    public sealed interface Stock permits TechStock, FinanceStock, RetailStock {}

    public static final class TechStock implements Stock {
        public final String symbol;

        public TechStock(String symbol) {
            this.symbol = symbol;
        }
    }

    public static final class FinanceStock implements Stock {
        public final String symbol;

        public FinanceStock(String symbol) {
            this.symbol = symbol;
        }
    }

    public static final class RetailStock implements Stock {
        public final String symbol;

        public RetailStock(String symbol) {
            this.symbol = symbol;
        }
    }

    // Record for immutable data structure
    public record MarketState(String type, double indexValue) {}

    private final ExecutorService executor = Executors.newFixedThreadPool(4);
    private final List<Stock> stocks = new ArrayList<>();
    private final HttpClient httpClient = HttpClient.newHttpClient();

    public StockMarketSimulation() {
        stocks.add(new TechStock("AAPL"));
        stocks.add(new FinanceStock("JPM"));
        stocks.add(new RetailStock("WMT"));
    }

    public void simulateMarket() {
        executor.submit(() -> simulateScenario("Bull Market", 1.05));
        executor.submit(() -> simulateScenario("Bear Market", 0.95));
        executor.submit(() -> simulateScenario("Market Crash", 0.7));
    }

    private void simulateScenario(String scenario, double multiplier) {
        double index = ThreadLocalRandom.current().nextDouble(1000, 3000);
        for (int i = 0; i < 5; i++) {
            index *= multiplier;
            sendMarketUpdate(new MarketState(scenario, index));
            try {
                Thread.sleep(1000);
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        }
    }

    private void sendMarketUpdate(MarketState state) {
        HttpRequest request = HttpRequest.newBuilder()
            .uri(URI.create("http://localhost:8080/market-update"))
            .timeout(Duration.ofSeconds(2))
            .header("Content-Type", "application/json")
            .POST(HttpRequest.BodyPublishers.ofString(
                "{ \"type\": \"" + state.type() + "\", \"indexValue\": " + state.indexValue() + " }"
            ))
            .build();

        httpClient.sendAsync(request, HttpResponse.BodyHandlers.ofString())
            .thenApply(HttpResponse::body)
            .thenAccept(response -> System.out.println("Update sent: " + response))
            .exceptionally(e -> {
                System.err.println("Error sending update: " + e.getMessage());
                return null;
            });
    }

    public void shutdown() {
        executor.shutdown();
    }

    public static void main(String[] args) {
        StockMarketSimulation simulation = new StockMarketSimulation();
        simulation.simulateMarket();
        Runtime.getRuntime().addShutdownHook(new Thread(simulation::shutdown));
    }
}
