public class CurrencyConverterApi {

    private static final String API_URL = "https://api.exchangerate-api.com/v4/latest/";
    private static final Map<String, CachedResponse> CACHE = new ConcurrentHashMap<>();

    public static void main(String[] args) throws IOException {
        HttpServer server = HttpServer.create(new InetSocketAddress(8080), 0);
        server.createContext("/convert", new CurrencyConverterHandler());
        server.setExecutor(Executors.newFixedThreadPool(10));
        server.start();
        System.out.println("Server started on port 8080...");
    }

    static class CachedResponse {
        final Map<String, Double> rates;
        final long timestamp;

        CachedResponse(Map<String, Double> rates, long timestamp) {
            this.rates = rates;
            this.timestamp = timestamp;
        }
    }

    static class CurrencyConverterHandler implements HttpHandler {
        @Override
        public void handle(HttpExchange exchange) throws IOException {
            if ("GET".equals(exchange.getRequestMethod())) {
                Map<String, String> queryParams = parseQueryParams(exchange.getRequestURI());

                String amountStr = queryParams.get("amount");
                String fromCurrency = queryParams.get("from");
                String toCurrency = queryParams.get("to");

                if (amountStr == null || fromCurrency == null || toCurrency == null) {
                    sendResponse(exchange, 400, "{\"error\": \"Missing required parameters\"}");
                    return;
                }

                try {
                    double amount = Double.parseDouble(amountStr);
                    double convertedAmount = convertCurrency(amount, fromCurrency.toUpperCase(), toCurrency.toUpperCase());
                    String jsonResponse = String.format("{\"convertedAmount\": %.2f}", convertedAmount);
                    sendResponse(exchange, 200, jsonResponse);
                } catch (Exception e) {
                    sendResponse(exchange, 500, "{\"error\": \"Conversion failed: " + e.getMessage() + "\"}");
                }
            } else {
                sendResponse(exchange, 405, "{\"error\": \"Method not allowed\"}");
            }
        }

        private double convertCurrency(double amount, String fromCurrency, String toCurrency) throws IOException, InterruptedException {
            Map<String, Double> rates = getExchangeRates(fromCurrency);
            if (!rates.containsKey(toCurrency)) {
                throw new IllegalArgumentException("Invalid target currency: " + toCurrency);
            }
            return amount * rates.get(toCurrency);
        }

        private Map<String, Double> getExchangeRates(String baseCurrency) throws IOException, InterruptedException {
            long currentTime = System.currentTimeMillis();
            CachedResponse cachedResponse = CACHE.get(baseCurrency);

            if (cachedResponse != null && (currentTime - cachedResponse.timestamp) <= 10 * 60 * 1000) {
                return cachedResponse.rates;
            }

            HttpClient client = HttpClient.newHttpClient();
            HttpRequest request = HttpRequest.newBuilder()
                    .uri(URI.create(API_URL + baseCurrency))
                    .GET()
                    .build();

            HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());
            Map<String, Object> responseBody = parseJson(response.body());

            Map<String, Double> exchangeRates = (Map<String, Double>) responseBody.get("rates");
            CACHE.put(baseCurrency, new CachedResponse(exchangeRates, currentTime));

            return exchangeRates;
        }

        private Map<String, String> parseQueryParams(URI uri) {
            Map<String, String> queryPairs = new HashMap<>();
            String query = uri.getQuery();
            if (query != null) {
                for (String pair : query.split("&")) {
                    String[] entry = pair.split("=");
                    queryPairs.put(entry[0], entry.length > 1 ? entry[1] : "");
                }
            }
            return queryPairs;
        }

        private void sendResponse(HttpExchange exchange, int statusCode, String response) throws IOException {
            exchange.getResponseHeaders().add("Content-Type", "application/json");
            exchange.sendResponseHeaders(statusCode, response.getBytes().length);
            try (OutputStream os = exchange.getResponseBody()) {
                os.write(response.getBytes());
            }
        }

        private Map<String, Object> parseJson(String json) throws IOException {
            Map<String, Object> map = new HashMap<>();
            json = json.replaceAll("[{}]", "");
            for (String pair : json.split(",")) {
                String[] entry = pair.split(":");
                String key = entry[0].trim().replaceAll("\"", "");
                String value = entry[1].trim();
                if (value.startsWith("\"")) {
                    map.put(key, value.replaceAll("\"", ""));
                } else if (value.contains(".")) {
                    map.put(key, Double.parseDouble(value));
                } else {
                    map.put(key, Integer.parseInt(value));
                }
            }
            return map;
        }
    }
}
