import com.sun.net.httpserver.HttpExchange;
import java.net.InetSocketAddress;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicReference;
import javax.json.Json;
import javax.json.JsonObject;
import java.lang.management.ManagementFactory;
import java.lang.management.OperatingSystemMXBean;

public class ServerHealthMonitor {
    private static final ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(1);
    private static final AtomicReference<JsonObject> healthDataCache = new AtomicReference<>();
    private static final int CACHE_TTL_SECONDS = 60;

    public static void main(String[] args) throws Exception {
        scheduleHealthDataCollection();
        startHttpServer();
    }

    private static void scheduleHealthDataCollection() {
        Runnable collectHealthData = () -> {
            OperatingSystemMXBean osBean = ManagementFactory.getPlatformMXBean(OperatingSystemMXBean.class);
            long freeMemory = Runtime.getRuntime().freeMemory();
            long totalMemory = Runtime.getRuntime().totalMemory();
            double systemLoad = osBean.getSystemLoadAverage();
            long diskSpace = new java.io.File(".").getFreeSpace();

            JsonObject healthData = Json.createObjectBuilder()
                    .add("memoryUsage", Json.createObjectBuilder()
                            .add("freeMemory", freeMemory)
                            .add("totalMemory", totalMemory))
                    .add("cpuLoad", systemLoad)
                    .add("diskUsage", diskSpace)
                    .build();

            healthDataCache.set(healthData);
        };

        scheduler.scheduleAtFixedRate(collectHealthData, 0, CACHE_TTL_SECONDS, TimeUnit.SECONDS);
    }

    private static void startHttpServer() throws Exception {
        HttpServer server = HttpServer.create(new InetSocketAddress(8080), 0);
        server.createContext("/health", new HealthEndpointHandler());
        server.setExecutor(Executors.newCachedThreadPool());
        server.start();
    }

    static class HealthEndpointHandler implements HttpHandler {
        @Override
        public void handle(HttpExchange exchange) {
            if ("GET".equals(exchange.getRequestMethod())) {
                JsonObject healthData = healthDataCache.get();
                String response = healthData != null ? healthData.toString() : "{}";
                exchange.getResponseHeaders().set("Content-Type", "application/json");
                try {
                    exchange.sendResponseHeaders(200, response.getBytes().length);
                    exchange.getResponseBody().write(response.getBytes());
                } catch (Exception e) {
                    e.printStackTrace();
                } finally {
                    exchange.close();
                }
            } else {
                try {
                    exchange.sendResponseHeaders(405, -1); // Method Not Allowed
                } catch (Exception e) {
                    e.printStackTrace();
                } finally {
                    exchange.close();
                }
            }
        }
    }
}
