use serde_json::Value;
use std::fs;
use std::path::Path;
use tokio::fs::File;
use tokio::io::{self, AsyncReadExt, AsyncWriteExt};
use tokio::runtime::Runtime;

async fn merge_json_files(input_paths: Vec<&str>, output_path: &str) -> io::Result<()> {
    let mut merged_json = serde_json::Map::new();

    for path in input_paths {
        let mut file = File::open(path).await?;
        let mut content = String::new();
        file.read_to_string(&mut content).await?;

        let json: Value = serde_json::from_str(&content)?;
        if let Some(obj) = json.as_object() {
            for (key, value) in obj {
                if merged_json.contains_key(key) {
                    // Validate JSON schema compatibility if needed
                    if merged_json[key] != value {
                        return Err(io::Error::new(io::ErrorKind::InvalidData, "Incompatible JSON schemas"));
                    }
                }
                merged_json.insert(key.clone(), value.clone());
            }
        } else {
            return Err(io::Error::new(io::ErrorKind::InvalidData, "Invalid JSON structure"));
        }
    }

    let final_json = Value::Object(merged_json);
    let mut output_file = File::create(output_path).await?;
    output_file.write_all(final_json.to_string().as_bytes()).await?;
    Ok(())
}

fn main() {
    let input_paths = vec!["input1.json", "input2.json", "input3.json"];
    let output_path = "merged_output.json";

    let rt = Runtime::new().unwrap();
    if let Err(e) = rt.block_on(merge_json_files(input_paths, output_path)) {
        eprintln!("Error merging JSON files: {}", e);
    }
}
