import java.io.IOException;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.util.Map;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;

import com.sun.net.httpserver.HttpServer;
import com.sun.net.httpserver.HttpHandler;
import com.sun.net.httpserver.HttpExchange;

import java.net.InetSocketAddress;
import java.util.UUID;

public class URLShortenerApplication {

    private static final Map<String, String> urlMapping = new ConcurrentHashMap<>();
    private static final Map<String, AtomicInteger> urlAccessCount = new ConcurrentHashMap<>();
    private static final String AUTH_TOKEN = "secureToken123"; // Replace with secure token

    public static void main(String[] args) throws IOException {
        HttpServer server = HttpServer.create(new InetSocketAddress(8080), 0);

        server.createContext("/shorten", new ShortenUrlHandler());
        server.createContext("/redirect", new RedirectHandler());

        server.setExecutor(null);
        server.start();
        System.out.println("Server started on port 8080");
    }

    static class ShortenUrlHandler implements HttpHandler {
        @Override
        public void handle(HttpExchange exchange) throws IOException {
            if (!"POST".equals(exchange.getRequestMethod())) {
                exchange.sendResponseHeaders(405, -1);
                return;
            }

            String authHeader = exchange.getRequestHeaders().getFirst("Authorization");
            if (authHeader == null || !authHeader.equals("Bearer " + AUTH_TOKEN)) {
                exchange.sendResponseHeaders(403, -1);
                return;
            }

            String originalUrl = new String(exchange.getRequestBody().readAllBytes());
            String shortAlias = UUID.randomUUID().toString().substring(0, 6);

            urlMapping.put(shortAlias, originalUrl);
            urlAccessCount.put(shortAlias, new AtomicInteger(0));

            exchange.sendResponseHeaders(200, shortAlias.length());
            exchange.getResponseBody().write(shortAlias.getBytes());
            exchange.getResponseBody().close();
        }
    }

    static class RedirectHandler implements HttpHandler {
        @Override
        public void handle(HttpExchange exchange) throws IOException {
            if (!"GET".equals(exchange.getRequestMethod())) {
                exchange.sendResponseHeaders(405, -1);
                return;
            }

            String shortAlias = exchange.getRequestURI().getPath().replace("/redirect/", "");
            String originalUrl = urlMapping.get(shortAlias);

            if (originalUrl == null) {
                exchange.sendResponseHeaders(404, -1);
                return;
            }

            urlAccessCount.get(shortAlias).incrementAndGet();

            HttpClient client = HttpClient.newHttpClient();
            HttpRequest request = HttpRequest.newBuilder().uri(URI.create(originalUrl)).build();

            CompletableFuture<HttpResponse<Void>> responseFuture =
                    client.sendAsync(request, HttpResponse.BodyHandlers.discarding());

            responseFuture.thenAccept(response -> {
                try {
                    exchange.getResponseHeaders().add("Location", originalUrl);
                    exchange.sendResponseHeaders(302, -1);
                    exchange.close();
                } catch (IOException e) {
                    e.printStackTrace();
                }
            }).exceptionally(error -> {
                try {
                    exchange.sendResponseHeaders(500, -1);
                    exchange.close();
                } catch (IOException e) {
                    e.printStackTrace();
                }
                return null;
            });
        }
    }
}
