import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.util.concurrent.ConcurrentHashMap;
import java.util.regex.Matcher;
import java.util.regex.Pattern;
import java.util.stream.Stream;
import java.util.Map;

public class AnalyticsDaemon {
    private static final Pattern IP_PATTERN = Pattern.compile("\\b(?:\\d{1,3}\\.){3}\\d{1,3}\\b");
    private final HttpClient httpClient;
    private final Map<String, Integer> threatScores = new ConcurrentHashMap<>();
    private final String logFilePath;
    private final String blacklistServiceUrl;

    public AnalyticsDaemon(String logFilePath, String blacklistServiceUrl) {
        this.httpClient = HttpClient.newHttpClient();
        this.logFilePath = logFilePath;
        this.blacklistServiceUrl = blacklistServiceUrl;
    }

    public void start() throws IOException {
        Path path = Paths.get(logFilePath);
        while (true) {
            try (Stream<String> lines = Files.lines(path)) {
                lines.forEach(this::processLogLine);
            } catch (IOException e) {
                System.err.println("Error reading log file: " + e.getMessage());
            }
            try {
                Thread.sleep(1000);  // Adjust the delay as needed
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        }
    }

    private void processLogLine(String line) {
        Matcher matcher = IP_PATTERN.matcher(line);
        while (matcher.find()) {
            String ipAddress = matcher.group();
            updateThreatScore(ipAddress);
        }
    }

    private void updateThreatScore(String ipAddress) {
        try {
            HttpRequest request = HttpRequest.newBuilder()
                    .uri(java.net.URI.create(blacklistServiceUrl + "?ip=" + ipAddress))
                    .GET()
                    .build();
            HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());
            if (response.body().equalsIgnoreCase("blacklisted")) {
                threatScores.merge(ipAddress, 1, Integer::sum);
                System.out.println("Updated threat score for IP: " + ipAddress + " -> " + threatScores.get(ipAddress));
            }
        } catch (Exception e) {
            System.err.println("Error fetching blacklist data for IP " + ipAddress + ": " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        if (args.length != 2) {
            System.err.println("Usage: java AnalyticsDaemon <logFilePath> <blacklistServiceUrl>");
            System.exit(1);
        }
        String logFilePath = args[0];
        String blacklistServiceUrl = args[1];

        AnalyticsDaemon daemon = new AnalyticsDaemon(logFilePath, blacklistServiceUrl);
        try {
            daemon.start();
        } catch (IOException e) {
            System.err.println("Error starting analytics daemon: " + e.getMessage());
        }
    }
}
