use tokio::fs;
use tokio::sync::mpsc;
use tokio::task;
use tokio::time;
use notify::{Watcher, RecursiveMode, watcher};
use std::sync::mpsc::channel;
use chrono::Local;
use sha2::{Sha256, Digest};
use std::fs::OpenOptions;
use std::io::Write;
use std::time::Duration;
use std::path::Path;

#[tokio::main]
async fn main() {
    let (tx, mut rx) = mpsc::channel(100);
    let (watch_tx, watch_rx) = channel();
    let mut watcher = watcher(watch_tx, Duration::from_secs(2)).unwrap();

    let dir_to_watch = "./your_directory";
    watcher.watch(dir_to_watch, RecursiveMode::Recursive).unwrap();

    task::spawn(async move {
        while let Ok(event) = watch_rx.recv() {
            tx.send(event).await.unwrap();
        }
    });

    let log_file = "file_changes.log";
    fs::create_dir_all(Path::new(dir_to_watch)).await.unwrap(); 

    while let Some(event) = rx.recv().await {
        if let notify::DebouncedEvent::Write(path) = event {
            if let Ok(metadata) = fs::metadata(&path).await {
                if let Ok(modified_time) = metadata.modified() {
                    let modified_time: chrono::DateTime<Local> = modified_time.into();
                    if let Ok(mut file) = fs::File::open(&path).await {
                        let mut hasher = Sha256::new();
                        let mut buffer = [0; 1024];
                        loop {
                            let n = file.read(&mut buffer).await.unwrap();
                            if n == 0 { break; }
                            hasher.update(&buffer[..n]);
                        }
                        let result = hasher.finalize();
                        let hash_hex: String = result.iter().map(|byte| format!("{:02x}", byte)).collect();
                        let log_entry = format!(
                            "File: {}, Modified: {}, Hash: {}\n",
                            path.to_string_lossy(), 
                            modified_time.format("%Y-%m-%d %H:%M:%S"), 
                            hash_hex
                        );
                        let mut logfile = OpenOptions::new().create(true).append(true).open(log_file).unwrap();
                        logfile.write_all(log_entry.as_bytes()).unwrap();
                    }
                }
            }
        }
    }
}
