public class WeatherApp {

    private static final List<String> cities = List.of("New York", "Los Angeles", "Chicago");
    private static final String apiKey = "your_api_key"; // Replace with your actual API key
    private static final String apiUrl = "https://api.weatherapi.com/v1/current.json?key=" + apiKey + "&q=";

    public static void main(String[] args) {
        HttpClient client = HttpClient.newBuilder()
                                      .version(HttpClient.Version.HTTP_2)
                                      .connectTimeout(Duration.ofSeconds(10))
                                      .build();

        while (true) {
            try {
                for (String city : cities) {
                    HttpRequest request = HttpRequest.newBuilder()
                                                     .uri(new URI(apiUrl + city))
                                                     .timeout(Duration.ofSeconds(10))
                                                     .build();

                    HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());

                    if (response.statusCode() == 200) {
                        parseAndDisplayWeatherData(response.body(), city);
                    } else {
                        System.out.println("Error: Invalid response for city " + city);
                    }
                }
                Thread.sleep(60000); // Update every 60 seconds

            } catch (HttpConnectTimeoutException e) {
                System.out.println("Error: Connection timed out. Retrying...");
            } catch (Exception e) {
                System.out.println("Error: " + e.getMessage());
            }
        }
    }

    private static void parseAndDisplayWeatherData(String json, String city) {
        JSONObject weatherData = new JSONObject(json);
        JSONObject current = weatherData.getJSONObject("current");

        double temperature = current.getDouble("temp_c");
        double windSpeed = current.getDouble("wind_kph");
        double precipitation = current.getDouble("precip_mm");

        System.out.println("Weather for " + city + " - Temperature: " + temperature + "°C, Wind Speed: " + windSpeed + " kph, Precipitation: " + precipitation + " mm");
