import java.io.IOException;
import java.net.URL;
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.SQLException;
import java.time.Instant;
import java.util.List;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.StructuredTaskScope;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import org.w3c.dom.Document;
import org.w3c.dom.NodeList;

public class RSSFeedProcessor {
    public static void main(String[] args) {
        List<String> rssFeedUrls = List.of(
                "https://example.com/feed1.xml",
                "https://example.com/feed2.xml" // Add more RSS feed URLs as needed
        );

        try (StructuredTaskScope<Void> scope = new StructuredTaskScope.ShutdownOnFailure()) {
            for (String url : rssFeedUrls) {
                scope.fork(() -> {
                    processFeed(url);
                    return null;
                });
            }
            scope.join();
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private static void processFeed(String url) {
        try {
            Document document = fetchRSSFeed(url);
            NodeList titles = document.getElementsByTagName("title");
            NodeList pubDates = document.getElementsByTagName("pubDate");
            storeFeedData(new RSSFeed(titles.item(1).getTextContent(), pubDates.item(0).getTextContent()));
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private static Document fetchRSSFeed(String url) throws Exception {
        URL feedUrl = new URL(url);
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        DocumentBuilder builder = factory.newDocumentBuilder();
        return builder.parse(feedUrl.openStream());
    }

    private static void storeFeedData(RSSFeed feed) {
        String dbUrl = "jdbc:sqlite:feeds.db";

        try (Connection conn = DriverManager.getConnection(dbUrl)) {
            String createTableQuery = """
                    CREATE TABLE IF NOT EXISTS feeds (
                        id INTEGER PRIMARY KEY AUTOINCREMENT,
                        title TEXT NOT NULL,
                        pubDate TEXT NOT NULL
                    );
                    """;
            String insertQuery = "INSERT INTO feeds (title, pubDate) VALUES (?, ?)";

            try (PreparedStatement createTableStmt = conn.prepareStatement(createTableQuery);
                 PreparedStatement insertStmt = conn.prepareStatement(insertQuery)) {
                createTableStmt.execute();
                insertStmt.setString(1, feed.title());
                insertStmt.setString(2, feed.pubDate());
                insertStmt.executeUpdate();
            }
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }

    sealed interface RSSData permits RSSFeed {
        String title();
        String pubDate();
    }

    record RSSFeed(String title, String pubDate) implements RSSData {}
}
