use async_std::stream::StreamExt;
use diesel::prelude::*;
use diesel::r2d2::{ConnectionManager, PooledConnection};
use diesel_migrations::{run_pending_migrations_in_directory, setup_database, MigrationError};
use dotenvy::dotenv;
use std::env;
use std::path::PathBuf;

type PgPool = r2d2::Pool<ConnectionManager<PgConnection>>;

#[async_std::main]
async fn main() {
    dotenv().ok();

    let database_url = env::var("DATABASE_URL").expect("DATABASE_URL must be set");
    let migration_dir: PathBuf = env::var("MIGRATION_DIR")
        .expect("MIGRATION_DIR must be set")
        .into();

    let manager = ConnectionManager::<PgConnection>::new(database_url);
    let pool: PgPool = r2d2::Pool::builder()
        .build(manager)
        .expect("Failed to create pool.");

    if let Err(e) = run_migrations(pool, migration_dir).await {
        eprintln!("Migration failed: {:?}", e);
    }
}

async fn run_migrations(pool: PgPool, migration_dir: PathBuf) -> Result<(), Box<dyn std::error::Error>> {
    let conn = pool.get()?;

    let migrations = fs::read_dir(migration_dir).await?;
    let mut migration_list = migrations
        .filter_map(|entry| async_std::future::ready(entry.ok()))
        .filter(|entry| async { entry.file_name().to_string_lossy().ends_with(".sql") })
        .collect::<Vec<_>>()
        .await;
    migration_list.sort_by_key(|entry| entry.file_name());

    conn.transaction::<_, diesel::result::Error, _>(|| {
        for migration in migration_list {
            let migration_path = migration.path();
            let sql = async_std::fs::read_to_string(migration_path).await?;
            diesel::sql_query(&sql).execute(&conn)?;

            log_migration(&conn, migration.file_name().to_string_lossy().to_string())?;
        }
        Ok(())
    })
}

fn log_migration(conn: &PooledConnection<ConnectionManager<PgConnection>>, migration_name: String) -> QueryResult<()> {
    diesel::sql_query(
        "INSERT INTO migration_history (migration_name, applied_at) VALUES ($1, NOW())",
    )
    .bind::<diesel::sql_types::Text, _>(migration_name)
    .execute(conn)?;
    Ok(())
}

// Ensure this table exists in your database
// CREATE TABLE migration_history (
//     id SERIAL PRIMARY KEY,
//     migration_name TEXT NOT NULL,
//     applied_at TIMESTAMP NOT NULL DEFAULT NOW()
// );
