import java.io.IOException;
import java.nio.file.*;
import java.nio.file.attribute.BasicFileAttributes;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.HashMap;
import java.util.Map;
import com.fasterxml.jackson.databind.ObjectMapper;

public class ConfigFileLogger {
    private static final String LOG_FILE = "file_changes_log.json";
    private static final ObjectMapper OBJECT_MAPPER = new ObjectMapper();
    private final Map<WatchKey, Path> keyMap = new HashMap<>();
    private final WatchService watchService;

    public ConfigFileLogger(Path path) throws IOException {
        this.watchService = FileSystems.getDefault().newWatchService();
        registerDirectory(path);
    }

    public void start() throws IOException, InterruptedException {
        while (true) {
            WatchKey key = watchService.take();
            Path dir = keyMap.get(key);
            if (dir == null) {
                continue;
            }
            for (WatchEvent<?> event : key.pollEvents()) {
                WatchEvent.Kind<?> kind = event.kind();
                if (kind == StandardWatchEventKinds.OVERFLOW) {
                    continue;
                }
                Path filePath = dir.resolve((Path) event.context());
                String timestamp = LocalDateTime.now().format(DateTimeFormatter.ISO_LOCAL_DATE_TIME);
                logChange(kind.name(), filePath.toString(), timestamp);
            }
            if (!key.reset()) {
                keyMap.remove(key);
                if (keyMap.isEmpty()) {
                    break;
                }
            }
        }
    }

    private void registerDirectory(Path path) throws IOException {
        Files.walkFileTree(path, new SimpleFileVisitor<>() {
            @Override
            public FileVisitResult preVisitDirectory(Path dir, BasicFileAttributes attrs) throws IOException {
                WatchKey key = dir.register(watchService, StandardWatchEventKinds.ENTRY_CREATE,
                        StandardWatchEventKinds.ENTRY_DELETE, StandardWatchEventKinds.ENTRY_MODIFY);
                keyMap.put(key, dir);
                return FileVisitResult.CONTINUE;
            }
        });
    }

    private void logChange(String eventType, String filePath, String timestamp) throws IOException {
        Map<String, String> logEntry = new HashMap<>();
        logEntry.put("event", eventType);
        logEntry.put("file", filePath);
        logEntry.put("timestamp", timestamp);
        OBJECT_MAPPER.writeValue(Files.newBufferedWriter(Path.of(LOG_FILE), StandardOpenOption.CREATE, StandardOpenOption.APPEND),
                logEntry);
    }

    public static void main(String[] args) {
        if (args.length < 1) {
            System.err.println("Usage: java ConfigFileLogger <directory_to_watch>");
            System.exit(1);
        }
        try {
            Path path = Paths.get(args[0]);
            ConfigFileLogger logger = new ConfigFileLogger(path);
            logger.start();
        } catch (IOException | InterruptedException e) {
            e.printStackTrace();
        }
    }
}
