import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.List;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.TimeUnit;

public class WebServerHealthMonitor {
    private static final String CONFIG_FILE = "config.txt";

    public static void main(String[] args) throws Exception {
        List<String> configLines = Files.readAllLines(Paths.get(CONFIG_FILE));
        int interval = Integer.parseInt(configLines.get(0)); // First line: interval in seconds
        List<String> urls = configLines.subList(1, configLines.size()); // Remaining lines: URLs

        HttpClient client = HttpClient.newHttpClient();

        while (true) {
            for (String url : urls) {
                URI uri = URI.create(url);
                HttpRequest request = HttpRequest.newBuilder(uri).build();

                CompletableFuture<Void> future = client.sendAsync(request, HttpResponse.BodyHandlers.ofString())
                        .thenAccept(response -> {
                            int statusCode = response.statusCode();
                            if (statusCode >= 200 && statusCode < 300) {
                                System.out.println("Server " + url + " is healthy: " + statusCode);
                            } else {
                                System.err.println("Server " + url + " returned error status: " + statusCode);
                            }
                        })
                        .exceptionally(ex -> {
                            System.err.println("Server " + url + " is not responding: " + ex.getMessage());
                            return null;
                        });

                future.join(); // Ensure the processing completes for each URL
            }
            TimeUnit.SECONDS.sleep(interval);
        }
    }
}
