async fn fetch_title(url: &str) -> Result<String, Error> {
    let response = reqwest::get(url).await?.text().await?;
    let document = scraper::Html::parse_document(&response);
    let selector = scraper::Selector::parse("title").unwrap();
    if let Some(element) = document.select(&selector).next() {
        Ok(element.text().collect::<Vec<_>>().concat())
    } else {
        Ok(String::from("No title found"))
    }
}

#[tokio::main]
async fn main() {
    let stdin = io::stdin();
    let urls: Vec<String> = stdin.lock().lines().filter_map(Result::ok).collect();
    let mut tasks = Vec::new();
    let mut results = HashMap::new();

    for url in urls {
        let url_clone = url.clone();
        tasks.push(task::spawn(async move {
            (url_clone, fetch_title(&url_clone).await)
        }));
    }

    for task in tasks {
        if let Ok((url, title)) = task.await {
            match title {
                Ok(title_str) => {
                    results.insert(url, title_str);
                }
                Err(e) => {
                    eprintln!("Error fetching {}: {}", url, e);
                }
            }
        }
    }

    println!("{:?}", results);
