import os
import json
import re
from concurrent.futures import ThreadPoolExecutor

def extract_comments(file_path, /):
    comments = []
    try:
        with open(file_path) as f:
            code = f.read()
        comments = re.findall(r'#.*', code)
    except Exception as e:
        print(f"Error processing {file_path}: {e}")
    return os.path.basename(file_path), comments

def extract_comments_from_directory(directory, /):
    comments_dict = {}

    py_files = [f for f in os.listdir(directory) if f.endswith('.py')]
    with ThreadPoolExecutor() as executor:
        futures = {executor.submit(extract_comments, os.path.join(directory, f)): f for f in py_files}
        for future in futures:
            if (result := future.result()):
                filename, comments = result
                comments_dict[filename] = comments

    return comments_dict

if __name__ == '__main__':
    directory = './scripts'
    comments_dict = extract_comments_from_directory(directory)
    with open('comments.json', 'w') as fout:
        json.dump(comments_dict, fout, indent=2)
