use async_std::net::TcpListener;
use async_std::prelude::*;
use serde::{Deserialize, Serialize};
use serde_json::Error as SerdeError;
use log::{info, error};
use simple_logger::SimpleLogger;

#[derive(Serialize, Deserialize)]
struct InputData {
    key: String,
    value: i32,
}

#[derive(Serialize, Deserialize)]
struct OutputData {
    key: String,
    result: i32,
}

async fn handle_client(mut stream: async_std::net::TcpStream) {
    let mut buffer = vec![0u8; 1024];
    match stream.read(&mut buffer).await {
        Ok(size) => {
            let data = &buffer[..size];
            match serde_json::from_slice::<InputData>(data) {
                Ok(input_data) => {
                    let output_data = OutputData {
                        key: input_data.key,
                        result: input_data.value * 2, // Example business logic: multiply value by 2.
                    };
                    match serde_json::to_vec(&output_data) {
                        Ok(response) => {
                            if let Err(e) = stream.write_all(&response).await {
                                error!("Failed to send response: {}", e);
                            }
                        }
                        Err(e) => error!("Failed to serialize response: {}", e),
                    }
                }
                Err(e) => {
                    error!("Failed to deserialize request: {}", e);
                }
            }
        }
        Err(e) => error!("Failed to read from stream: {}", e),
    }
}

#[async_std::main]
async fn main() -> std::io::Result<()> {
    SimpleLogger::new().init().unwrap();
    let listener = TcpListener::bind("127.0.0.1:8080").await?;
    info!("Server is listening on 127.0.0.1:8080");

    while let Ok((stream, _)) = listener.accept().await {
        async_std::task::spawn(handle_client(stream));
    }

    Ok(())
}
