import json
import argparse
import matplotlib.pyplot as plt
from collections import defaultdict

def parse_args():
    parser = argparse.ArgumentParser(description='Process JSON log files.')
    parser.add_argument('logfile_path', type=str, help='Path to the JSON log file.')
    parser.add_argument('--verbose', action='store_true', help='Increase output verbosity.')
    return parser.parse_args()

def process_log_file(path, verbose):
    error_stats = defaultdict(lambda: defaultdict(int))

    try:
        with open(path, 'r') as f:
            logs = json.load(f)
            for entry in logs:
                error_type = entry.get('error_type', 'Unknown')
                severity = entry.get('severity', 'Unknown')
                error_stats[error_type][severity] += 1
                if verbose:
                    print(f"Processed log entry: {entry}")

    except json.JSONDecodeError as e:
        print(f"JSON decode error: {e}")
    except FileNotFoundError as e:
        print(f"File not found: {e}")
    except Exception as e:
        print(f"Unhandled exception: {e}")

    return error_stats

def visualize_data(error_stats):
    error_types = list(error_stats.keys())
    severity_levels = set(level for levels in error_stats.values() for level in levels)

    figures, axes = plt.subplots(len(error_types), figsize=(10, 5 * len(error_types)))

    if len(error_types) == 1:
        axes = [axes]

    for i, error_type in enumerate(error_types):
        stats = error_stats[error_type]
        levels = list(stats.keys())
        counts = list(stats.values())

        axes[i].bar(levels, counts)
        axes[i].set_xlabel('Severity Level')
        axes[i].set_ylabel('Count')
        axes[i].set_title(f'Error Type: {error_type}')

    plt.tight_layout()
    plt.show()

def main():
    args = parse_args()

    error_stats = process_log_file(args.logfile_path, args.verbose)

    if args.verbose:
        print("Compiled error statistics:")
        for error_type, levels in error_stats.items():
            for level, count in levels.items():
                print(f"Type: {error_type}, Severity: {level}, Count: {count}")

    visualize_data(error_stats)

if __name__ == '__main__':
    main()
