import com.fasterxml.jackson.databind.ObjectMapper;
import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.apache.kafka.clients.consumer.KafkaConsumer;

import javax.sql.DataSource;
import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.SQLException;
import java.time.Duration;
import java.util.List;
import java.util.Properties;

public sealed class TransactionProcessor permits ECommerceTransactionService {
    public static final ObjectMapper OBJECT_MAPPER = new ObjectMapper();
}

public final class ECommerceTransactionService extends TransactionProcessor {

    private final KafkaConsumer<String, String> kafkaConsumer;
    private final DataSource dataSource;

    public ECommerceTransactionService(Properties kafkaProps, DataSource dataSource) {
        this.kafkaConsumer = new KafkaConsumer<>(kafkaProps);
        this.dataSource = dataSource;
    }

    public void processTransactions(String topic) {
        kafkaConsumer.subscribe(List.of(topic));

        while (true) {
            for (ConsumerRecord<String, String> record : kafkaConsumer.poll(Duration.ofMillis(1000))) {
                try (Connection connection = dataSource.getConnection()) {
                    connection.setAutoCommit(false);
                    Transaction transaction = parseTransaction(record.value());
                    if (isValid(transaction)) {
                        persistTransaction(connection, transaction);
                        connection.commit();
                    } else {
                        connection.rollback();
                    }
                } catch (Exception e) {
                    System.err.println("Error processing transaction: " + e.getMessage());
                }
            }
        }
    }

    private Transaction parseTransaction(String json) throws Exception {
        Object transactionObject = OBJECT_MAPPER.readValue(json, Object.class);
        if (transactionObject instanceof Transaction transaction) {
            return transaction;
        } else {
            throw new IllegalArgumentException("Invalid transaction type");
        }
    }

    private boolean isValid(Transaction transaction) {
        return transaction.amount() > 0 && transaction.currency() != null;
    }

    private void persistTransaction(Connection connection, Transaction transaction) throws SQLException {
        String sql = "INSERT INTO transactions (id, amount, currency, timestamp) VALUES (?, ?, ?, ?)";
        try (PreparedStatement stmt = connection.prepareStatement(sql)) {
            stmt.setString(1, transaction.id());
            stmt.setDouble(2, transaction.amount());
            stmt.setString(3, transaction.currency());
            stmt.setString(4, transaction.timestamp());
            stmt.executeUpdate();
        }
    }
}

public record Transaction(String id, double amount, String currency, String timestamp) {}
