use rusoto_core::Region;
use rusoto_s3::{PutObjectRequest, S3Client, S3};
use std::path::PathBuf;
use tokio::fs;
use tokio::task::spawn_blocking;
use tokio::sync::mpsc;
use notify::{Watcher, watcher, RecursiveMode, DebouncedEvent};
use log::{info, error};
use std::time::Duration;
use std::sync::mpsc::channel;

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    env_logger::init();

    let (tx, rx) = mpsc::channel(100);
    let s3_client = S3Client::new(Region::UsEast1);

    let (notify_tx, notify_rx) = channel();
    let mut watcher = watcher(notify_tx, Duration::from_secs(10))?;
    watcher.watch("/path/to/watch", RecursiveMode::Recursive)?;

    let process_rx = async {
        while let Ok(event) = notify_rx.recv() {
            if let DebouncedEvent::Create(path) = event {
                tx.send(path).await.expect("Failed to send path");
            }
        }
    };

    tokio::spawn(process_rx);

    while let Some(path) = rx.recv().await {
        let s3_client = s3_client.clone();
        spawn_blocking(move || upload_to_s3(s3_client, path)).await?;
    }

    Ok(())
}

fn upload_to_s3(s3_client: S3Client, path: PathBuf) -> Result<(), Box<dyn std::error::Error>> {
    let file_content = fs::read(&path)?;
    let bucket_name = "my-s3-bucket";

    let put_request = PutObjectRequest {
        bucket: bucket_name.to_string(),
        key: path.file_name().unwrap().to_str().unwrap().to_string(),
        body: Some(file_content.into()),
        ..Default::default()
    };

    match s3_client.put_object(put_request).sync() {
        Ok(_) => info!("Successfully uploaded: {:?}", path),
        Err(e) => error!("Failed to upload {:?}: {:?}", path, e),
    }

    Ok(())
}
