import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.WebSocket;
import java.net.URI;
import java.util.concurrent.Flow;
import java.util.concurrent.SubmissionPublisher;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.Executors;
import java.util.concurrent.ExecutorService;
import java.util.stream.DoubleStream;
import com.google.gson.Gson;

public class StockMarketApp {

    private static final ConcurrentHashMap<String, StockData> stockMap = new ConcurrentHashMap<>();
    private static final SubmissionPublisher<StockMetrics> metricsPublisher = new SubmissionPublisher<>();
    private static final ExecutorService executor = Executors.newVirtualThreadPerTaskExecutor(); // JDK 21 Scoped Executor

    public static void main(String[] args) {
        startWebSocketConnection();

        metricsPublisher.subscribe(new MetricsSubscriber());
        Runtime.getRuntime().addShutdownHook(new Thread(() -> shutdown()));
    }

    private static void startWebSocketConnection() {
        HttpClient.newHttpClient()
                .newWebSocketBuilder()
                .buildAsync(URI.create("wss://simulated-stock-api.exchange/data"), new StockWebSocketListener());
    }

    private static record StockData(String symbol, double price) {
    }

    private static record StockMetrics(String symbol, double movingAverage, double fluctuation) {
    }

    private static class StockWebSocketListener implements WebSocket.Listener {
        @Override
        public void onText(WebSocket webSocket, CharSequence data, boolean last) {
            webSocket.request(1);
            StockData stockData = new Gson().fromJson(data.toString(), StockData.class);

            // Process data
            stockMap.compute(stockData.symbol(), (symbol, existingData) -> {
                executor.execute(() -> calculateMetrics(symbol, stockData));
                return stockData;
            });
        }
    }

    private static void calculateMetrics(String symbol, StockData newData) {
        stockMap.compute(symbol, (s, existingData) -> {
            if (existingData != null) {
                double movingAverage = (newData.price() + existingData.price()) / 2;
                double fluctuation = Math.abs(newData.price() - existingData.price());
                metricsPublisher.submit(new StockMetrics(symbol, movingAverage, fluctuation));
            }
            return newData;
        });
    }

    private static class MetricsSubscriber implements Flow.Subscriber<StockMetrics> {
        private Flow.Subscription subscription;

        @Override
        public void onSubscribe(Flow.Subscription subscription) {
            this.subscription = subscription;
            subscription.request(1);
        }

        @Override
        public void onNext(StockMetrics item) {
            System.out.println(new Gson().toJson(item)); // Simulating REST JSON Response
            subscription.request(1);
        }

        @Override
        public void onError(Throwable throwable) {
            throwable.printStackTrace();
        }

        @Override
        public void onComplete() {
            System.out.println("Metrics stream completed.");
        }
    }

    private static void shutdown() {
        try {
            metricsPublisher.close();
            stockMap.clear();
            executor.shutdown();
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}
