use std::fs;
use std::path::{Path, PathBuf};
use std::sync::{Arc, Mutex};
use tokio::sync::Semaphore;
use tokio::task;
use image::{imageops::FilterType, GenericImageView, ImageOutputFormat};
use tokio::fs as tokio_fs;

const MAX_WORKERS: usize = 10;
const TARGET_WIDTH: u32 = 800;
const TARGET_HEIGHT: u32 = 600;

#[tokio::main]
async fn main() {
    let source_dir = "source_directory";
    let target_dir = "target_directory";

    // Create target directory if it doesn't exist
    tokio_fs::create_dir_all(target_dir).await.unwrap();

    let files = Arc::new(Mutex::new(
        fs::read_dir(source_dir)
            .unwrap()
            .filter_map(|entry| entry.ok())
            .map(|entry| entry.path())
            .filter(|path| is_image_file(path))
            .collect::<Vec<PathBuf>>(),
    ));

    let semaphore = Arc::new(Semaphore::new(MAX_WORKERS));
    let mut handles = Vec::new();

    while let Some(file) = files.lock().unwrap().pop() {
        let permit = semaphore.clone().acquire_owned().await.unwrap();
        let target_dir = target_dir.to_owned();

        handles.push(task::spawn(async move {
            if let Err(e) = process_image(&file, &target_dir).await {
                eprintln!("Error processing file {:?}: {}", file, e);
            }
            drop(permit);
        }));
    }

    for handle in handles {
        handle.await.unwrap();
    }
}

async fn process_image(file_path: &Path, target_dir: &str) -> tokio::io::Result<()> {
    let img = tokio::task::block_in_place(|| image::open(file_path)).map_err(|e| {
        eprintln!("Failed to open image file {:?}: {}", file_path, e);
        std::io::Error::new(std::io::ErrorKind::Other, "Failed to open image")
    })?;

    // Resize logic while maintaining aspect ratio
    let resized_img = tokio::task::block_in_place(|| {
        img.thumbnail(TARGET_WIDTH, TARGET_HEIGHT)
    });

    // Save resized image to target directory
    let file_name = file_path
        .file_name()
        .ok_or_else(|| std::io::Error::new(std::io::ErrorKind::Other, "Invalid file name"))?;
    let target_path = Path::new(target_dir).join(file_name);

    let mut output_file = tokio_fs::File::create(target_path).await?;
    tokio::task::block_in_place(|| {
        resized_img
            .write_to(
                &mut std::io::BufWriter::new(&mut output_file),
                ImageOutputFormat::Jpeg(80),
            )
            .map_err(|e| {
                std::io::Error::new(
                    std::io::ErrorKind::Other,
                    format!("Failed to save image: {}", e),
                )
            })
    })?;

    // Move original file (optional, delegating current task afterwards)
    tokio_fs::remove_file(file_path).await?;

    Ok(())
}

fn is_image_file(path: &Path) -> bool {
    if let Some(ext) = path.extension() {
        ext.eq_ignore_ascii_case("jpg")
            || ext.eq_ignore_ascii_case("jpeg")
            || ext.eq_ignore_ascii_case("png")
    } else {
        false
    }
}
