use std::fs::File;
use std::io::{self, BufReader, BufWriter};
use std::path::Path;
use std::process;
use std::thread;
use std::sync::mpsc;
use flate2::write::GzEncoder;
use flate2::Compression;

const MAX_THREADS: usize = 8;

fn compress_file(path: &Path) -> io::Result<()> {
    let file = File::open(path)?;
    let mut reader = BufReader::new(file);

    let gz_path = path.with_extension("gz");
    let gz_file = File::create(gz_path)?;
    let mut writer = BufWriter::new(gz_file);
    let mut encoder = GzEncoder::new(writer, Compression::default());

    io::copy(&mut reader, &mut encoder)?;
    encoder.finish()?;
    Ok(())
}

fn main() {
    let mut filenames = Vec::new();

    for line in io::stdin().lock().lines() {
        match line {
            Ok(filename) => filenames.push(filename),
            Err(_) => {
                eprintln!("Failed to read filename");
                process::exit(1);
            }
        }
    }

    let (tx, rx) = mpsc::channel();
    let mut handles = Vec::new();

    for filename in filenames {
        let tx = tx.clone();
        let handle = thread::spawn(move || {
            let path = Path::new(&filename);
            if let Err(err) = compress_file(path) {
                eprintln!("Error compressing file {}: {}", filename, err);
            }
            tx.send(()).unwrap();
        });
        handles.push(handle);

        if handles.len() >= MAX_THREADS {
            rx.recv().unwrap();
            handles.pop();
        }
    }

    for handle in handles {
        handle.join().unwrap();
    }
}
