import com.fasterxml.jackson.databind.ObjectMapper;

import java.io.*;
import java.net.http.HttpServer;
import java.net.InetSocketAddress;
import java.net.URI;
import java.util.HashMap;
import java.util.Map;

import org.apache.tika.Tika;
import org.apache.tika.exception.TikaException;

public class DocumentPreviewService {
    public static void main(String[] args) throws IOException {
        HttpServer server = HttpServer.create(new InetSocketAddress(8080), 0);

        server.createContext("/summarize", exchange -> {
            if ("POST".equalsIgnoreCase(exchange.getRequestMethod())) {
                InputStream inputStream = exchange.getRequestBody();
                try {
                    String metadata = processFile(inputStream);
                    exchange.sendResponseHeaders(200, metadata.getBytes().length);
                    OutputStream outputStream = exchange.getResponseBody();
                    outputStream.write(metadata.getBytes());
                    outputStream.close();
                } catch (Exception e) {
                    String errorMessage = "{\"error\": \"Failed to process file\"}";
                    exchange.sendResponseHeaders(500, errorMessage.getBytes().length);
                    OutputStream outputStream = exchange.getResponseBody();
                    outputStream.write(errorMessage.getBytes());
                    outputStream.close();
                }
            } else {
                exchange.sendResponseHeaders(405, -1); // Method Not Allowed
            }
        });

        server.start();
        System.out.println("Server started on port 8080");
    }

    private static String processFile(InputStream inputStream) throws IOException, TikaException {
        Tika tika = new Tika();
        Map<String, Object> metadata = new HashMap<>();

        byte[] fileContent = inputStream.readAllBytes();
        String textContent = tika.parseToString(new ByteArrayInputStream(fileContent));
        String fileType = tika.detect(fileContent);

        int wordCount = textContent.split("\\s+").length;
        String detectedLanguage = guessLanguage(fileContent);

        metadata.put("summary", summarizeText(textContent, 50));
        metadata.put("wordCount", wordCount);
        metadata.put("fileType", fileType);
        metadata.put("detectedLanguage", detectedLanguage);

        ObjectMapper objectMapper = new ObjectMapper();
        return objectMapper.writeValueAsString(metadata);
    }

    private static String summarizeText(String text, int maxWords) {
        String[] words = text.split("\\s+");
        if (words.length <= maxWords) {
            return text;
        } else {
            return String.join(" ", java.util.Arrays.copyOfRange(words, 0, maxWords)) + "...";
        }
    }

    private static String guessLanguage(byte[] content) {
        String utf8String = new String(content, java.nio.charset.StandardCharsets.UTF_8);
        if (utf8String.chars().allMatch(c -> (c < 128))) {
            return "English (basic heuristic, UTF-8 detected)";
        }
        return "Unknown";
    }
}
